mapper.select:
SELECT a.user_id userId,a.user_b_id userBId,a.type cleanType, CASE a.type WHEN 1 THEN '搭电' WHEN 2 THEN '拖车' WHEN 3 THEN '送胎' ELSE '救援' END AS cleanName,CONCAT('不限车型') carName,a.rescue_number cleanIndentNumber,price*0.8 amount,a.state indentState,b.url imgUrl, CONCAT(1) isEvaluation,a.create_time createTime,CONCAT(3) resource,rescue_name rescueName, current_position currentPosition FROM app_rescue_indent as a LEFT JOIN app_rescue_img as b on a.type = b.type WHERE a.user_b_id = #{userBId} AND a.state <> ''
AND a.state = #{type}
order by createTime DESC LIMIT #{pagesize},20
